SELECT term_id, questions_count, answers_count
FROM analysis_metrics
WHERE term_id = 1;

SELECT COUNT(*) AS active_questionnaires_count
FROM questionnaires
WHERE researcher_id = 0 AND status = 'active';

SELECT title
FROM questionnaires
WHERE status = 'active';

SELECT term_id, accepted_count
FROM analysis_metrics
ORDER BY accepted_count DESC;

SELECT word, last_updated_at
FROM terms
ORDER BY last_updated_at DESC;

SELECT term_id, COUNT(*) AS term_count
FROM analysis_metrics
GROUP BY term_id;

SELECT answer_text, is_accepted
FROM answers
WHERE is_accepted = 1;

SELECT COUNT(answer_id) AS total_answers
FROM answers
WHERE user_id = 1;
